import type { ExternalConnectorOptions } from '../../services/jobs';

const readRawString = (raw: Record<string, unknown>, ...names: string[]): string | null => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'string' && value.trim()) return value.trim();
    }
  }
  return null;
};

const readRawNumber = (raw: Record<string, unknown>, fallback: number, ...names: string[]): number => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'number' && !Number.isNaN(value)) return value;
    }
  }
  return fallback;
};

const readRawBool = (raw: Record<string, unknown>, fallback: boolean, ...names: string[]): boolean => {
  for (const name of names) {
    for (const [key, value] of Object.entries(raw)) {
      if (key.toLowerCase() !== name.toLowerCase()) continue;
      if (typeof value === 'boolean') return value;
    }
  }
  return fallback;
};

export const defaultConnectorOptions = (): ExternalConnectorOptions => ({
  searchPath: '',
  detailPathTemplate: null,
  documentKeyField: 'soHoaDon',
  detailKeyParam: 'billId',
  pageSize: 100,
  parallelJobs: 4,
  timeoutSeconds: 60,
  maxRetries: 3,
  dateOffsetDays: 0,
  syncLookbackDays: 1,
  defaultFromDate: null,
  defaultToDate: null,
  apiKeyHeader: 'x-api-key',
  apiKey: null,
  apiKeyConfigKey: null,
  fetchDetailBeforeImport: true,
});

export const parseConnectorOptions = (json?: string | null): ExternalConnectorOptions => {
  if (!json) return defaultConnectorOptions();
  try {
    const raw = JSON.parse(json) as Record<string, unknown>;
    const defaults = defaultConnectorOptions();
    return {
      searchPath: readRawString(raw, 'searchPath') ?? defaults.searchPath,
      detailPathTemplate: readRawString(raw, 'detailPathTemplate'),
      documentKeyField: readRawString(raw, 'documentKeyField') ?? defaults.documentKeyField,
      detailKeyParam: readRawString(raw, 'detailKeyParam') ?? defaults.detailKeyParam,
      pageSize: readRawNumber(raw, defaults.pageSize, 'pageSize'),
      parallelJobs: readRawNumber(raw, defaults.parallelJobs, 'parallelJobs'),
      timeoutSeconds: readRawNumber(raw, defaults.timeoutSeconds, 'timeoutSeconds'),
      maxRetries: readRawNumber(raw, defaults.maxRetries, 'maxRetries'),
      dateOffsetDays: readRawNumber(raw, defaults.dateOffsetDays, 'dateOffsetDays'),
      syncLookbackDays: readRawNumber(raw, defaults.syncLookbackDays, 'syncLookbackDays'),
      defaultFromDate: readRawString(raw, 'defaultFromDate'),
      defaultToDate: readRawString(raw, 'defaultToDate'),
      apiKeyHeader: readRawString(raw, 'apiKeyHeader') ?? defaults.apiKeyHeader,
      apiKey: readRawString(raw, 'apiKey'),
      apiKeyConfigKey: readRawString(raw, 'apiKeyConfigKey'),
      fetchDetailBeforeImport: readRawBool(raw, defaults.fetchDetailBeforeImport, 'fetchDetailBeforeImport'),
    };
  } catch {
    return defaultConnectorOptions();
  }
};

export const serializeConnectorOptions = (options: ExternalConnectorOptions): string => {
  const clean = defaultConnectorOptions();
  clean.searchPath = options.searchPath;
  clean.detailPathTemplate = options.detailPathTemplate ?? null;
  clean.documentKeyField = options.documentKeyField;
  clean.detailKeyParam = options.detailKeyParam;
  clean.pageSize = options.pageSize;
  clean.parallelJobs = options.parallelJobs;
  clean.timeoutSeconds = options.timeoutSeconds;
  clean.maxRetries = options.maxRetries;
  clean.dateOffsetDays = options.dateOffsetDays;
  clean.syncLookbackDays = options.syncLookbackDays;
  clean.defaultFromDate = options.defaultFromDate ?? null;
  clean.defaultToDate = options.defaultToDate ?? null;
  clean.apiKeyHeader = options.apiKeyHeader;
  clean.fetchDetailBeforeImport = options.fetchDetailBeforeImport;
  if (options.apiKey?.trim()) {
    clean.apiKey = options.apiKey.trim();
  }
  return JSON.stringify(clean);
};

const trimPath = (value: string): string =>
  value.trim().replace(/^['"]+|['"]+$/g, '');

export const sanitizeConnectorOptions = (
  options: ExternalConnectorOptions,
): ExternalConnectorOptions => ({
  ...options,
  searchPath: trimPath(options.searchPath ?? ''),
  detailPathTemplate: options.detailPathTemplate
    ? trimPath(options.detailPathTemplate) || null
    : null,
  documentKeyField: (options.documentKeyField ?? 'soHoaDon').trim(),
  detailKeyParam: (options.detailKeyParam ?? 'billId').trim(),
  apiKeyHeader: (options.apiKeyHeader ?? 'x-api-key').trim() || 'x-api-key',
});

export const computeRangeFromOffset = (opt: ExternalConnectorOptions): { from: string; to: string } => {
  const to = new Date();
  to.setUTCDate(to.getUTCDate() - (opt.dateOffsetDays ?? 0));
  const from = new Date(to);
  from.setUTCDate(from.getUTCDate() - Math.max(0, (opt.syncLookbackDays ?? 1) - 1));
  const fmt = (d: Date) => d.toISOString().slice(0, 10);
  return { from: fmt(from), to: fmt(to) };
};

export const resolveInitialSyncRange = (
  opt: ExternalConnectorOptions,
): { from: string; to: string } | null => {
  if (opt.defaultFromDate && opt.defaultToDate) {
    return { from: opt.defaultFromDate, to: opt.defaultToDate };
  }
  if (opt.dateOffsetDays !== undefined || opt.syncLookbackDays !== undefined) {
    return computeRangeFromOffset(opt);
  }
  return null;
};

export const stripApiKeyFromOptions = (
  opt: ExternalConnectorOptions,
): { options: ExternalConnectorOptions; hasStoredApiKey: boolean } => {
  const hasStoredApiKey = Boolean(opt.apiKey?.trim());
  return {
    hasStoredApiKey,
    options: {
      ...opt,
      apiKey: null,
      apiKeyConfigKey: null,
    },
  };
};

export const API_KEY_MASK = '••••••••••••';

export const isApiKeyMaskValue = (value: string): boolean =>
  value === API_KEY_MASK || /^•+$/.test(value);

export const resolveApiKeyForPayload = (
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): string | null => {
  const typed = apiKeyInput.trim();
  if (typed && !isApiKeyMaskValue(typed)) return typed;
  if (hasStoredApiKey) return null;
  return parseConnectorOptions(existingJson).apiKey?.trim() || null;
};

export const buildOptionsForSave = (
  options: ExternalConnectorOptions,
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): ExternalConnectorOptions => {
  const sanitized = sanitizeConnectorOptions(options);
  const resolvedKey = resolveApiKeyForPayload(apiKeyInput, existingJson, hasStoredApiKey);
  const payload: ExternalConnectorOptions = {
    ...sanitized,
    apiKeyConfigKey: null,
  };
  if (resolvedKey) {
    payload.apiKey = resolvedKey;
  } else {
    delete payload.apiKey;
  }
  return payload;
};

export type ConnectorValidationResult = { ok: true } | { ok: false; message: string };

export const validateConnectorDateDefaults = (
  options: ExternalConnectorOptions,
): ConnectorValidationResult => {
  const from = options.defaultFromDate?.trim();
  const to = options.defaultToDate?.trim();
  if (!from && !to) return { ok: true };
  if (Boolean(from) !== Boolean(to)) {
    return { ok: false, message: 'Cần nhập cả Từ ngày và Đến ngày mặc định (hoặc để trống cả hai)' };
  }
  if (!from || !to) return { ok: true };

  const fromDate = new Date(from);
  const toDate = new Date(to);
  if (Number.isNaN(fromDate.getTime()) || Number.isNaN(toDate.getTime())) {
    return { ok: false, message: 'Ngày mặc định không hợp lệ' };
  }
  if (fromDate.getFullYear() < 2000 || toDate.getFullYear() < 2000) {
    return { ok: false, message: 'Năm ngày mặc định phải từ 2000 trở lên' };
  }
  if (from > to) {
    return { ok: false, message: 'Từ ngày mặc định không được lớn hơn Đến ngày' };
  }
  return { ok: true };
};

export const validateConnectionDraft = (
  externalBaseUrl: string | null | undefined,
  options: ExternalConnectorOptions,
  apiKeyInput: string,
  existingJson?: string | null,
  hasStoredApiKey = false,
): ConnectorValidationResult => {
  if (!externalBaseUrl?.trim()) {
    return { ok: false, message: 'Base URL là bắt buộc' };
  }
  const sanitized = sanitizeConnectorOptions(options);
  if (!sanitized.searchPath?.trim()) {
    return { ok: false, message: 'Search path là bắt buộc' };
  }
  const merged = buildOptionsForSave(sanitized, apiKeyInput, existingJson, hasStoredApiKey);
  if (!merged.apiKey && !hasStoredApiKey) {
    return { ok: false, message: 'API key là bắt buộc — nhập key mới hoặc lưu key trước đó' };
  }
  return validateConnectorDateDefaults(sanitized);
};
