import type { DataSyncRunDetail, DataSyncRunListItem } from '../../services/jobs/dataSyncModels';

export const EXTERNAL_CONNECTOR_LABELS: Record<string, string> = {
  'reva-fm-hoa-don': 'Hóa đơn bán',
  'reva-fm-phieu-thu': 'Phiếu thu',
  'reva-fm-phieu-chi': 'Phiếu chi',
};

export const connectorLabel = (configKey: string): string =>
  EXTERNAL_CONNECTOR_LABELS[configKey] ?? configKey;

export const resolveExternalRunDisplayStatus = (run: {
  status: string;
  checkpointSummary?: { failed: number };
}): string => {
  if (run.checkpointSummary && run.checkpointSummary.failed > 0 && run.status === 'Success') {
    return 'Partial';
  }
  return run.status;
};

export const formatExternalRunStatsLine = (run: DataSyncRunDetail | DataSyncRunListItem): string => {
  const summary = 'conversionSummary' in run ? run.conversionSummary : undefined;
  const converted = run.documentsConverted ?? summary?.documentsConverted ?? 0;
  const failed =
    run.documentsFailed ??
    summary?.documentsFailed ??
    ('checkpointSummary' in run ? run.checkpointSummary?.failed : 0) ??
    0;
  const total =
    summary?.documentsTotal ??
    ('checkpointSummary' in run ? run.checkpointSummary?.total : 0) ??
    0;
  const pullOnly = summary?.documentsPullOnly ?? 0;

  const parts: string[] = [`${converted.toLocaleString('vi-VN')} convert`];
  if (pullOnly > 0) {
    parts.push(`${pullOnly.toLocaleString('vi-VN')} pull only`);
  }
  if (failed > 0) {
    parts.push(`${failed.toLocaleString('vi-VN')} lỗi`);
  }
  if (total > 0) {
    parts.push(`${total.toLocaleString('vi-VN')} tổng`);
  }
  return parts.join(' · ');
};

export const buildErrorMessageMap = (
  samples: DataSyncRunDetail['errorSamples'],
  checkpoints?: Array<{ documentKey: string; errorMessage?: string | null }>,
): Map<string, string> => {
  const map = new Map<string, string>();
  for (const sample of samples ?? []) {
    if (sample.documentKey) {
      map.set(sample.documentKey, sample.message);
    }
  }
  for (const cp of checkpoints ?? []) {
    if (cp.documentKey && cp.errorMessage && !map.has(cp.documentKey)) {
      map.set(cp.documentKey, cp.errorMessage);
    }
  }
  return map;
};
