/** Client-side list filter — parity DataSyncSetConfigPage / erp-form-context §8.7 search. */
export const filterBySearchQuery = <T>(
  rows: T[],
  query: string,
  getHaystack: (row: T) => string,
): T[] => {
  const q = query.trim().toLowerCase();
  if (!q) return rows;
  return rows.filter((row) => getHaystack(row).toLowerCase().includes(q));
};

export const formatListCountMeta = (
  loading: boolean,
  total: number,
  filtered: number,
  searchQuery: string,
  itemLabel: string,
): string => {
  if (loading) return 'Đang tải…';
  const q = searchQuery.trim();
  if (q) return `${filtered} / ${total} ${itemLabel}`;
  return `${total} ${itemLabel}`;
};
